366	#[cfg(test)]
367	mod tests {
368	    use super::*;
369	    use std::path::Path;
370	    use std::sync::atomic::{AtomicU64, Ordering};
371	    use std::time::{SystemTime, UNIX_EPOCH};
372	    use std::{fs, path::PathBuf};
373	
374	    use crate::test_tmp_root::{resolve_tmp_root, should_keep_tempdir};
375	
376	    /// Per-process counter so same-nanosecond tempdir collisions
377	    /// yield distinct paths when tests run in parallel.
378	    static COUNTER: AtomicU64 = AtomicU64::new(0);
379	
380	    /// RAII tempdir for `config` tests — sibling of `Fixture` /
381	    /// `FixturePor` / `CliFixture`, scaled to the much smaller
382	    /// "write a config.toml and parse it" use case. Replaces the
383	    /// pre-0.41.1-6.4 `cfg_tempdir(tag) -> PathBuf` helper, which
384	    /// had no `Drop` and leaked one dir per test invocation.
385	    ///
386	    /// Uses the shared `resolve_tmp_root` (`$VC_X1_TEST_TMPDIR` →
387	    /// `std::env::temp_dir()`) and honors `should_keep_tempdir()`
388	    /// (`$VC_X1_TEST_KEEP`) so the same env-var knobs control all
389	    /// fixture types uniformly.
390	    struct CfgTempDir {
391	        dir: PathBuf,
392	    }
393	
394	    impl CfgTempDir {
395	        fn new(tag: &str) -> Self {
396	            let ts = SystemTime::now()
397	                .duration_since(UNIX_EPOCH)
398	                .map(|d| d.as_nanos())
399	                .unwrap_or(0); // OK: clock error → 0 is harmless for unique tempdir naming
400	            let n = COUNTER.fetch_add(1, Ordering::SeqCst);
401	            let dir = resolve_tmp_root().join(format!("vc-x1-cfg-{tag}-{ts}-{n}"));
402	            fs::create_dir_all(&dir).expect("mkdir cfg tempdir");
403	            Self { dir }
404	        }
405	
406	        fn dir(&self) -> &Path {
407	            &self.dir
408	        }
409	    }
410	
411	    impl Drop for CfgTempDir {
412	        fn drop(&mut self) {
413	            if should_keep_tempdir() {
414	                eprintln!("VC_X1_TEST_KEEP set; preserving {}", self.dir.display());
415	            } else {
416	                let _ = fs::remove_dir_all(&self.dir);
417	            }
418	        }
419	    }
420	
421	    /// Write `contents` to `<dir>/config.toml`. Returns the
422	    /// `CfgTempDir` guard alongside the file path so callers can
423	    /// keep the guard alive for the test's scope.
424	    fn write_cfg(tag: &str, contents: &str) -> (CfgTempDir, PathBuf) {
425	        let cfg = CfgTempDir::new(tag);
426	        let path = cfg.dir().join("config.toml");
427	        fs::write(&path, contents).unwrap();
428	        (cfg, path)
429	    }
430	
431	    /// `Drop` removes the tempdir on success: keep the path
432	    /// outside the inner scope, drop the guard, and verify the
433	    /// directory is gone. Pins the leak fix that landed in
434	    /// 0.41.1-6.4.
435	    #[test]
436	    fn cfg_tempdir_drop_cleans_up() {
437	        let path: PathBuf;
438	        {
439	            let cfg = CfgTempDir::new("drop-cleanup");
440	            path = cfg.dir().to_path_buf();
441	            assert!(path.exists(), "tempdir must exist while guard is alive");
442	        }
443	        assert!(
444	            !path.exists(),
445	            "tempdir must be removed after CfgTempDir drops, got: {}",
446	            path.display()
447	        );
448	    }
449	
450	    #[test]
451	    fn missing_file_returns_default() {
452	        let cfg = CfgTempDir::new("missing");
453	        let path = cfg.dir().join("nonexistent.toml");
454	        let parsed = load_from(&path).unwrap();
455	        assert_eq!(parsed, UserConfig::default());
456	    }
457	
458	    #[test]
459	    fn empty_file_returns_default() {
460	        let (_cfg, path) = write_cfg("empty", "");
461	        let cfg = load_from(&path).unwrap();
462	        assert_eq!(cfg, UserConfig::default());
463	    }
464	
465	    #[test]
466	    fn full_schema_parses() {
467	        let (_cfg, path) = write_cfg(
468	            "full",
469	            r#"[default]
470	account = "home"
471	debug   = "trace"
472	
473	[account.home]
474	repo.default          = "remote"
475	repo.category.remote  = "git@github.com:winksaville"
476	repo.category.local   = "~/test-fixtures"
477	
478	[account.work]
479	repo.default          = "remote"
480	repo.category.remote  = "git@github.com:anthropic"
481	repo.category.local   = "/work/fixtures"
482	"#,
483	        );
484	        let cfg = load_from(&path).unwrap();
485	        assert_eq!(cfg.default_account.as_deref(), Some("home"));
486	        assert_eq!(cfg.default_debug.as_deref(), Some("trace"));
487	        assert_eq!(cfg.accounts.len(), 2);
488	
489	        let home = cfg.accounts.get("home").expect("home account");
490	        assert_eq!(home.repo_default.as_deref(), Some("remote"));
491	        assert_eq!(
492	            home.repo_category.get("remote").map(String::as_str),
493	            Some("git@github.com:winksaville")
494	        );
495	        assert_eq!(
496	            home.repo_category.get("local").map(String::as_str),
497	            Some("~/test-fixtures")
498	        );
499	
500	        let work = cfg.accounts.get("work").expect("work account");
501	        assert_eq!(work.repo_default.as_deref(), Some("remote"));
502	        assert_eq!(
503	            work.repo_category.get("remote").map(String::as_str),
504	            Some("git@github.com:anthropic")
505	        );
506	    }
507	
508	    #[test]
509	    fn account_only_no_default_section() {
510	        // No [default]; one account. accounts populated, top-level None.
511	        let (_cfg, path) = write_cfg(
512	            "no-default",
513	            r#"[account.solo]
514	repo.default          = "remote"
515	repo.category.remote  = "git@github.com:wink"
516	"#,
517	        );
518	        let cfg = load_from(&path).unwrap();
519	        assert!(cfg.default_account.is_none());
520	        assert!(cfg.default_debug.is_none());
521	        assert_eq!(cfg.accounts.len(), 1);
522	        assert!(cfg.accounts.contains_key("solo"));
523	    }
