525	    #[test]
526	    fn top_level_repo_shorthand() {
527	        // Single-account shorthand — top-level [repo], no [account.*].
528	        let (_cfg, path) = write_cfg(
529	            "top-level",
530	            r#"[repo]
531	default          = "remote"
532	category.remote  = "git@github.com:wink"
533	category.local   = "~/test-fixtures"
534	"#,
535	        );
536	        let cfg = load_from(&path).unwrap();
537	        assert!(cfg.accounts.is_empty());
538	        let tl = cfg.top_level_repo.expect("top_level_repo populated");
539	        assert_eq!(tl.repo_default.as_deref(), Some("remote"));
540	        assert_eq!(
541	            tl.repo_category.get("remote").map(String::as_str),
542	            Some("git@github.com:wink")
543	        );
544	        assert_eq!(
545	            tl.repo_category.get("local").map(String::as_str),
546	            Some("~/test-fixtures")
547	        );
548	    }
