550	    #[test]
551	    fn mixing_top_level_and_accounts_errors() {
552	        // Both top-level [repo] and [account.*] is ambiguous.
553	        let (_cfg, path) = write_cfg(
554	            "mixed",
555	            r#"[repo]
556	default = "remote"
557	
558	[account.home]
559	repo.default = "remote"
560	"#,
561	        );
562	        let err = load_from(&path).unwrap_err().to_string();
563	        assert!(err.contains("mixing top-level [repo]"), "got: {err}");
564	    }
