578	    #[test]
579	    fn unknown_keys_ignored() {
580	        // Forward-compat: unknown sections/sub-keys silently dropped.
581	        let (_cfg, path) = write_cfg(
582	            "unknown",
583	            r#"[account.home]
584	repo.category.remote = "git@github.com:wink"
585	repo.category.local  = "~/fixtures"
586	repo.unknown-subkey  = "ignored"
