14	/// Read the other repo path from a repo's `.vc-config.toml`.
15	///
16	/// Returns the `workspace.other-repo` value, which is the relative path
17	/// to the counterpart repo from the repo's directory.
18	pub fn other_repo_from_config(
19	    config: &HashMap<String, String>,
20	) -> Result<String, Box<dyn std::error::Error>> {
