44	/// Problems found with an ochid trailer, with details for reporting.
45	#[derive(Debug)]
46	pub struct OchidIssues {
47	    /// None if prefix is correct, Some((actual_prefix, expected_prefix)) if wrong.
48	    pub wrong_prefix: Option<(String, String)>,
49	    /// None if length is correct, Some((actual_len, expected_len)) if wrong.
50	    pub wrong_length: Option<(usize, usize)>,
51	    /// true if the bare ID does not resolve in the other repo.
52	    pub not_found: bool,
53	    /// The bare ID extracted from the ochid value.
54	    pub bare_id: String,
55	}
56	
57	impl OchidIssues {
58	    pub fn any(&self) -> bool {
59	        self.wrong_prefix.is_some() || self.wrong_length.is_some() || self.not_found
60	    }
61	
62	    pub fn summary(&self) -> String {
63	        let mut parts = Vec::new();
64	        if let Some((ref actual, ref expected)) = self.wrong_prefix {
65	            parts.push(format!("prefix: {actual} (want {expected})"));
66	        }
67	        if let Some((actual, expected)) = self.wrong_length {
68	            parts.push(format!("len: {actual} (want {expected})"));
69	        }
70	        if self.not_found {
71	            parts.push(format!("not found: {}", self.bare_id));
72	        }
73	        parts.join(", ")
74	    }
75	}
76	
77	/// Validate an ochid trailer value against expected prefix, length, and other repo.
78	pub fn validate_ochid(
79	    value: &str,
80	    other_prefix: &str,
81	    id_len: usize,
82	    other_workspace: &Workspace,
83	    other_repo: &Arc<ReadonlyRepo>,
84	) -> OchidIssues {
85	    // Extract the actual prefix (everything before the bare ID)
86	    let bare_id = extract_bare_id(value);
87	    let actual_prefix = &value[..value.len() - bare_id.len()];
88	
89	    let wrong_prefix = if actual_prefix != other_prefix {
90	        Some((actual_prefix.to_string(), other_prefix.to_string()))
91	    } else {
